import React, { useState } from 'react';
import { itemAPI } from '../services/api';

const SimpleItemForm = ({ onItemAdded }) => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: '',
    location: '',
    type: 'LOST'
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const categories = [
    'Electronics', 'Jewelry', 'Documents', 'Clothing', 
    'Accessories', 'Books', 'Keys', 'Wallet', 'Phone', 
    'Bag', 'Watch', 'Glasses', 'Other'
  ];

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    console.log('Submitting item:', formData);

    try {
      // Create a simple API call without authentication headers
      const response = await fetch('http://localhost:8080/api/items/add', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();
      console.log('Item added successfully:', data);

      if (data.id) {
        onItemAdded(data);
        setFormData({
          title: '',
          description: '',
          category: '',
          location: '',
          type: 'LOST'
        });
        setError('');
      } else {
        setError('Failed to add item: ' + (data.message || 'Unknown error'));
      }
    } catch (error) {
      console.error('Error adding item:', error);
      setError('Network error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card">
      <div className="card-header">
        <h4 className="mb-0">📦 Simple Item Form (No Auth)</h4>
        <div className="text-muted small">
          This form bypasses authentication to test item addition
        </div>
      </div>
      <div className="card-body">
        {error && <div className="alert alert-danger">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label">Title *</label>
            <input
              type="text"
              className="form-control"
              name="title"
              value={formData.title}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-3">
            <label className="form-label">Description</label>
            <textarea
              className="form-control"
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows="3"
            />
          </div>

          <div className="mb-3">
            <label className="form-label">Category *</label>
            <select
              className="form-select"
              name="category"
              value={formData.category}
              onChange={handleChange}
              required
            >
              <option value="">Select a category</option>
              {categories.map(category => (
                <option key={category} value={category}>{category}</option>
              ))}
            </select>
          </div>

          <div className="mb-3">
            <label className="form-label">Location</label>
            <input
              type="text"
              className="form-control"
              name="location"
              value={formData.location}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-3">
            <label className="form-label">Type *</label>
            <select
              className="form-select"
              name="type"
              value={formData.type}
              onChange={handleChange}
              required
            >
              <option value="LOST">🔍 Lost Item</option>
              <option value="FOUND">✅ Found Item</option>
            </select>
          </div>

          <button type="submit" className="btn btn-primary w-100" disabled={loading}>
            {loading ? 'Adding...' : '📦 Add Item (No Auth)'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default SimpleItemForm;
